            {showSettings && (
                <div className="p-3 grid gap-3 animate-slide-up border-t border-gray-700 bg-gray-900/50 max-h-[60vh] overflow-y-auto custom-scrollbar">

                    {/* BROADCAST VIEWS - NEW SECTION */}
