import React, { createContext, useState, useEffect, ReactNode } from 'react';
import { AuctionState, AuctionStatus, Team, Player, AuctionLog, UserProfile, UserRole, AuctionContextType, AuctionCategory, Sponsor, ProjectorLayout, OBSLayout, AdminViewOverride, BiddingStatus } from '../types';
import { db, auth } from '../firebase';
import firebase from 'firebase/compat/app';

const BID_INTERVAL = 30;
const SUPER_ADMIN_EMAIL = "superadmin@smsports.com";

const initialState: AuctionState = {
  players: [],
  teams: [],
  unsoldPlayers: [],
  categories: [],
  status: AuctionStatus.NotStarted,
  currentPlayerId: null,
  currentPlayerIndex: null,
  currentBid: null,
  highestBidder: null,
  timer: BID_INTERVAL,
  bidIncrement: 10,
  bidSlabs: [],
  auctionLog: [],
  biddingStatus: 'ON', // Default ON
  playerSelectionMode: 'MANUAL',
  sponsors: [],
  sponsorConfig: { showOnOBS: true, showOnProjector: true, loopInterval: 5 },
  auctionLogoUrl: '',
  tournamentName: '',
  projectorLayout: 'STANDARD',
  obsLayout: 'STANDARD',
  adminViewOverride: null
};

export const AuctionContext = createContext<AuctionContextType | null>(null);

export const AuctionProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [state, setState] = useState<AuctionState>(initialState);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [activeAuctionId, setActiveAuctionId] = useState<string | null>(null);

  // Restore session & Derive Role
  useEffect(() => {
     const unsubscribe = auth.onAuthStateChanged((user) => {
         if (user) {
             if (user.isAnonymous) {
                 const storedSession = localStorage.getItem('sm_sports_team_session');
                 if (storedSession) {
                     const sessionData = JSON.parse(storedSession);
                     if (sessionData.role === 'TEAM_OWNER') {
                         setUserProfile({
                             uid: user.uid,
                             email: `team_${sessionData.teamId}`,
                             name: `Team ${sessionData.teamId}`,
                             role: UserRole.TEAM_OWNER,
                             teamId: sessionData.teamId
                         });
                         if (sessionData.auctionId) setActiveAuctionId(sessionData.auctionId);
                         return;
                     }
                 }
             }

             if (user.email) {
                 if (user.email === SUPER_ADMIN_EMAIL) {
                     // SUPER ADMIN ROLE
                     setUserProfile({
                         uid: user.uid,
                         email: user.email,
                         name: "Super Owner",
                         role: UserRole.SUPER_ADMIN
                     });
                 } else if (user.email.startsWith('team_')) {
                     try {
                         const idPart = user.email.split('@')[0].split('_')[1];
                         setUserProfile({
                             uid: user.uid,
                             email: user.email,
                             name: user.displayName || `Team ${idPart}`,
                             role: UserRole.TEAM_OWNER,
                             teamId: idPart 
                         });
                     } catch (e) {
                         setUserProfile({ uid: user.uid, email: user.email, name: 'Viewer', role: UserRole.VIEWER });
                     }
                 } else {
                     // ADMIN ROLE
                     setUserProfile({ 
                         uid: user.uid, 
                         email: user.email, 
                         name: user.displayName || user.email.split('@')[0], // Prioritize displayName
                         role: UserRole.ADMIN 
                     });
                 }
             } else {
                setUserProfile({ uid: user.uid, email: 'viewer', name: 'Guest', role: UserRole.VIEWER });
             }
         } else {
             setUserProfile(null);
             localStorage.removeItem('sm_sports_team_session');
         }
     });
     return () => unsubscribe();
  }, []);

  // MAIN LISTENER
  useEffect(() => {
    if (!activeAuctionId) return;

    const auctionDocRef = db.collection('auctions').doc(activeAuctionId);

    const unsubAuction = auctionDocRef.onSnapshot((docSnap) => {
        if (docSnap.exists) {
            setError(null);
            const data = docSnap.data() as any; 

            setState(prev => {
                const highestBidder = prev.teams.find(t => String(t.id) === String(data.highestBidderId)) || null;

                // BACKWARD COMPATIBILITY: If biddingStatus missing, assume ON (unless biddingEnabled was specifically false)
                let status: BiddingStatus = 'ON';
                if (data.biddingStatus) {
                    status = data.biddingStatus;
                } else if (data.biddingEnabled === false) {
                    status = 'PAUSED';
                }

                return {
                    ...prev,
                    status: data.status || AuctionStatus.NotStarted,
                    currentBid: data.currentBid,
                    timer: data.timer || BID_INTERVAL,
                    currentPlayerId: data.currentPlayerId,
                    highestBidder,
                    bidIncrement: data.bidIncrement || 10,
                    bidSlabs: data.slabs || [],
                    biddingStatus: status,
                    playerSelectionMode: data.playerSelectionMode || 'MANUAL',
                    auctionLogoUrl: data.logoUrl || '',
                    tournamentName: data.title || '',
                    sponsorConfig: data.sponsorConfig || { showOnOBS: true, showOnProjector: true, loopInterval: 5 },
                    projectorLayout: data.projectorLayout || 'STANDARD',
                    obsLayout: data.obsLayout || 'STANDARD',
                    adminViewOverride: data.adminViewOverride || null
                };
            });
        } else {
            setError("Auction Not Found");
        }
    }, (err: any) => {
        console.error("Firestore Main Sync Error:", err);
        handleError(err);
    });

    const unsubTeams = auctionDocRef.collection('teams').onSnapshot((s) => {
        const teams = s.docs.map(d => ({ id: d.id, ...d.data() } as Team));
        setState(p => ({ ...p, teams }));
    }, (err) => console.error("Teams sync error", err));

    const unsubPlayers = auctionDocRef.collection('players').onSnapshot((s) => {
        const players = s.docs.map(d => ({ id: d.id, ...d.data() } as Player));
        players.sort((a,b) => {
            const idA = Number(a.id);
            const idB = Number(b.id);
            if (!isNaN(idA) && !isNaN(idB)) return idA - idB;
            return String(a.id).localeCompare(String(b.id));
        });
        setState(p => ({ ...p, players, unsoldPlayers: players }));
    }, (err) => console.error("Players sync error", err));

    const unsubCats = auctionDocRef.collection('categories').onSnapshot((s) => {
        const categories = s.docs.map(d => ({ id: d.id, ...d.data() } as AuctionCategory));
        setState(p => ({ ...p, categories }));
    }, (err) => console.error("Categories sync error", err));

    const unsubSponsors = auctionDocRef.collection('sponsors').onSnapshot((s) => {
        const sponsors = s.docs.map(d => ({ id: d.id, ...d.data() } as Sponsor));
        setState(p => ({ ...p, sponsors }));
    }, (err) => console.error("Sponsors sync error", err));

    const unsubLog = auctionDocRef.collection('log').orderBy('timestamp', 'desc').limit(50).onSnapshot((s) => {
         const auctionLog = s.docs.map(d => {
              const data = d.data();
              let ts = Date.now();
              if (data.timestamp && typeof data.timestamp.toMillis === 'function') {
                  ts = data.timestamp.toMillis();
              } else if (typeof data.timestamp === 'number') {
                  ts = data.timestamp;
              }
              return { ...data, timestamp: ts } as AuctionLog;
          });
        setState(p => ({ ...p, auctionLog }));
    }, (err) => console.error("Log sync error", err));

    return () => {
        unsubAuction();
        unsubTeams();
        unsubPlayers();
        unsubCats();
        unsubSponsors();
        unsubLog();
    };
  }, [activeAuctionId]);

  const handleError = (err: any) => {
      if (err.message?.includes("database") || err.code === 'not-found') {
          setError("Database not found. Go to Firebase Console -> Firestore Database -> Create Database");
      } else if (err.code === 'permission-denied') {
          setError("Permission denied. Check Firestore Security Rules.");
      }
  };

  const joinAuction = (id: string) => {
      setActiveAuctionId(id);
  };

  const calculateNextBid = () => {
      const { currentPlayerId, players, currentBid, categories, bidIncrement, bidSlabs } = state;
      const currentPlayer = players.find(p => String(p.id) === String(currentPlayerId));
      if (!currentPlayer) return 0;

      const basePrice = Number(currentPlayer.basePrice || 0);
      const currentPrice = Number(currentBid || 0);

      if (currentPrice === 0) {
          return basePrice > 0 ? basePrice : 0;
      }

      let effectiveIncrement = Number(bidIncrement || 10);
      let ruleFound = false;

      if (categories.length > 0) {
          const playerCat = categories.find(c => c.name === currentPlayer.category);
          if (playerCat) {
              if (playerCat.slabs && playerCat.slabs.length > 0) {
                  const activeSlab = [...playerCat.slabs].sort((a, b) => b.from - a.from).find(s => currentPrice >= s.from);
                  if (activeSlab) {
                      effectiveIncrement = Number(activeSlab.increment);
                      ruleFound = true;
                  }
              }
              if (!ruleFound && playerCat.bidIncrement > 0) {
                  effectiveIncrement = Number(playerCat.bidIncrement);
                  ruleFound = true;
              }
          }
      }

      if (!ruleFound && bidSlabs && bidSlabs.length > 0) {
          const activeSlab = [...bidSlabs].sort((a, b) => b.from - a.from).find(s => currentPrice >= s.from);
          if (activeSlab) {
              effectiveIncrement = Number(activeSlab.increment);
              ruleFound = true; 
          }
      }

      const startPoint = Math.max(currentPrice, basePrice);
      return startPoint + effectiveIncrement;
  };

  const updateBiddingStatus = async (status: BiddingStatus) => {
      if (!activeAuctionId) return;
      try {
          await db.collection('auctions').doc(activeAuctionId).update({
              biddingStatus: status,
              biddingEnabled: status === 'ON' // Maintain legacy field
          });
      } catch(e: any) {
          console.error("Toggle Bidding Error", e);
          alert("Failed to toggle bidding: " + e.message);
      }
  };

  const toggleSelectionMode = async () => {
      if (!activeAuctionId) return;
      try {
          const newMode = state.playerSelectionMode === 'AUTO' ? 'MANUAL' : 'AUTO';
          await db.collection('auctions').doc(activeAuctionId).update({
              playerSelectionMode: newMode
          });
      } catch(e: any) {
          console.error("Toggle Selection Mode Error", e);
      }
  };

  const updateTheme = async (type: 'PROJECTOR' | 'OBS', layout: string) => {
      if (!activeAuctionId) return;
      try {
          const updateData = type === 'PROJECTOR' ? { projectorLayout: layout } : { obsLayout: layout };
          await db.collection('auctions').doc(activeAuctionId).update(updateData);
      } catch(e: any) {
          console.error("Update Theme Error", e);
      }
  };

  const setAdminView = async (view: AdminViewOverride | null) => {
      if (!activeAuctionId) return;
      try {
          await db.collection('auctions').doc(activeAuctionId).update({
              adminViewOverride: view
          });
      } catch (e: any) {
          console.error("Set Admin View Error", e);
      }
  };

  const placeBid = async (teamId: number | string, amount: number) => {
      if (!activeAuctionId) return;

      // Strict check using new status
      if (state.biddingStatus !== 'ON') {
          alert("Bidding is currently disabled by the Admin.");
          return;
      }

      const auctionRef = db.collection('auctions').doc(activeAuctionId);

      try {
        await db.runTransaction(async (transaction) => {
            const auctionSnap = await transaction.get(auctionRef);
            if (!auctionSnap.exists) throw "No auction";
            const data = auctionSnap.data() as any;

            if (data?.status !== AuctionStatus.InProgress) throw "Auction not in progress";

            // Server side check
            if (data?.biddingStatus && data.biddingStatus !== 'ON') throw "Bidding is currently paused by Admin";
            if (data?.biddingEnabled === false && !data.biddingStatus) throw "Bidding is currently paused by Admin";

            const currentPlayerId = data?.currentPlayerId;
            if (!currentPlayerId) throw "No active player";

            const playerRef = auctionRef.collection('players').doc(String(currentPlayerId));
            const playerSnap = await transaction.get(playerRef);
            if (!playerSnap.exists) throw "Player data missing";
            const playerData = playerSnap.data() as Player;
            const basePrice = Number(playerData.basePrice || 0);

            const teamRef = auctionRef.collection('teams').doc(String(teamId));
            const teamSnap = await transaction.get(teamRef);
            if (!teamSnap.exists) throw "Team not found";
            const teamData = teamSnap.data() as Team;

            const currentHighest = Number(data?.currentBid || 0);

            if (amount < basePrice) {
                throw `Bid (${amount}) cannot be lower than Base Price (${basePrice})`;
            }

            if (currentHighest > 0 && amount <= currentHighest) {
                throw `Bid (${amount}) must be higher than current bid (${currentHighest})`;
            }

            if (Number(teamData.budget) < amount) throw "Insufficient funds";

            transaction.update(auctionRef, {
                currentBid: Number(amount),
                highestBidderId: String(teamId),
                timer: BID_INTERVAL 
            });

            const logRef = auctionRef.collection('log').doc();
            transaction.set(logRef, {
                message: `${teamData.name} bids ${amount}`,
                timestamp: Date.now(), 
                type: 'BID'
            });
        });
        console.log("Bid placed successfully");
      } catch (e: any) {
          console.error("Bid Error:", e);
          alert(`Bid Failed: ${e.message || e}`);
          throw e;
      }
  };

  const correctPlayerSale = async (playerId: string, newTeamId: string | null, newPrice: number) => {
      // ... (Rest of logic remains same, removed for brevity, assuming minimal context changes needed)
      // This function logic was unchanged, keeping it as is in implementation
      if (!activeAuctionId) return;
      const auctionRef = db.collection('auctions').doc(activeAuctionId);

      try {
          await db.runTransaction(async (transaction) => {
              const playerRef = auctionRef.collection('players').doc(playerId);
              const playerSnap = await transaction.get(playerRef);
              if (!playerSnap.exists) throw "Player not found";
              const playerData = playerSnap.data() as Player;

              if (playerData.status === 'SOLD' && playerData.soldTo) {
                  const oldTeamObj = state.teams.find(t => t.name === playerData.soldTo);

                  if (oldTeamObj) {
                      const oldTeamRef = auctionRef.collection('teams').doc(String(oldTeamObj.id));
                      const oldTeamSnap = await transaction.get(oldTeamRef);
                      if (oldTeamSnap.exists) {
                          const oldTeamData = oldTeamSnap.data() as Team;
                          const refundAmount = Number(playerData.soldPrice || 0);
                          const updatedBudget = Number(oldTeamData.budget) + refundAmount;
                          const updatedPlayers = (oldTeamData.players || []).filter(p => String(p.id) !== String(playerId));
                          transaction.update(oldTeamRef, {
                              budget: updatedBudget,
                              players: updatedPlayers
                          });
                      }
                  }
              }

              if (newTeamId) {
                  const newTeamRef = auctionRef.collection('teams').doc(newTeamId);
                  const newTeamSnap = await transaction.get(newTeamRef);
                  if (!newTeamSnap.exists) throw "New Team not found";
                  const newTeamData = newTeamSnap.data() as Team;

                  if (Number(newTeamData.budget) < newPrice) {
                      throw `Team ${newTeamData.name} has insufficient budget (${newTeamData.budget}) for correction price ${newPrice}`;
                  }

                  const newBudget = Number(newTeamData.budget) - Number(newPrice);
                  const playerSummary = {
                      id: String(playerData.id),
                      name: String(playerData.name),
                      category: String(playerData.category),
                      soldPrice: Number(newPrice)
                  };

                  const currentPlayers = newTeamData.players || [];
                  const filteredPlayers = currentPlayers.filter(p => String(p.id) !== String(playerId));

                  transaction.update(newTeamRef, {
                      budget: newBudget,
                      players: [...filteredPlayers, playerSummary]
                  });

                  transaction.update(playerRef, {
                      status: 'SOLD',
                      soldPrice: Number(newPrice),
                      soldTo: newTeamData.name
                  });
              } else {
                  transaction.update(playerRef, {
                      status: firebase.firestore.FieldValue.delete(),
                      soldPrice: firebase.firestore.FieldValue.delete(),
                      soldTo: firebase.firestore.FieldValue.delete()
                  });
              }

              const logRef = auctionRef.collection('log').doc();
              transaction.set(logRef, {
                  message: `ADMIN CORRECTION: ${playerData.name} ${newTeamId ? 'reassigned' : 'unsold'}.`,
                  timestamp: Date.now(),
                  type: 'SYSTEM'
              });
          });
      } catch (e: any) {
          console.error("Correction Error:", e);
          throw e; 
      }
  };

  const sellPlayer = async (customTeamId?: string | number, customPrice?: number) => {
      if (!activeAuctionId) {
          alert("Error: No active auction ID. Try refreshing.");
          return;
      }
      const auctionRef = db.collection('auctions').doc(activeAuctionId);

      try {
        console.log("Starting Sell Process...");
        const auctionSnap = await auctionRef.get();
        if (!auctionSnap.exists) throw new Error("Auction not found");
        const auctionData = auctionSnap.data() as any;
        const currentPlayerId = auctionData.currentPlayerId;

        let targetTeamId = customTeamId ? String(customTeamId) : auctionData.highestBidderId;
        if (targetTeamId) targetTeamId = String(targetTeamId); 

        const finalBid = customPrice !== undefined ? Number(customPrice) : Number(auctionData.currentBid || 0);

        if (!currentPlayerId) throw new Error("No current player active.");
        if (!targetTeamId) throw new Error("No bidder found. Use 'Unsold' or select a team manually.");

        const playerRef = auctionRef.collection('players').doc(String(currentPlayerId));
        const teamRef = auctionRef.collection('teams').doc(targetTeamId);

        const playerSnap = await playerRef.get();
        if (!playerSnap.exists) throw new Error("Player data missing");
        const playerData = playerSnap.data() as Player;

        const teamSnap = await teamRef.get();
        if (!teamSnap.exists) throw new Error("Winning team not found. ID: " + targetTeamId);

        const teamData = teamSnap.data() as Team;
        const currentBudget = Number(teamData.budget || 0);
        const newBudget = currentBudget - finalBid;
        const currentPlayers = teamData.players || [];

        const playerSummary = {
            id: String(playerData.id),
            name: String(playerData.name || 'Unknown'),
            category: String(playerData.category || 'Uncategorized'),
            soldPrice: finalBid
        };

        const updatedPlayers = [...currentPlayers, playerSummary];

        await teamRef.update({ budget: newBudget, players: updatedPlayers });
        await playerRef.update({ status: 'SOLD', soldPrice: finalBid, soldTo: teamData.name });

        await auctionRef.update({
            status: AuctionStatus.Sold,
            currentBid: null,
            highestBidderId: null,
            timer: BID_INTERVAL
        });

        await auctionRef.collection('log').add({
            message: `SOLD! ${playerData.name} to ${teamData.name} for ${finalBid}`,
            timestamp: Date.now(),
            type: 'SOLD'
        });

        if (state.playerSelectionMode === 'AUTO') {
             setTimeout(() => startAuction(), 3000);
        }

      } catch (e: any) {
          console.error("Sell Error:", e);
          alert("SELL FAILED: " + (e.message || e));
      }
  };

  const passPlayer = async () => {
      if (!activeAuctionId) return;
      const auctionRef = db.collection('auctions').doc(activeAuctionId);

      try {
        const docSnap = await auctionRef.get();
        const data = docSnap.data() as any;
        const currentPlayerId = data.currentPlayerId;

        let playerName = "Player";
        if (currentPlayerId) {
            const playerRef = auctionRef.collection('players').doc(String(currentPlayerId));
            const pDoc = await playerRef.get();
            if (pDoc.exists) {
                playerName = (pDoc.data() as any).name;
                await playerRef.update({ status: 'UNSOLD' });
            }
        }

        await auctionRef.update({
            status: AuctionStatus.Unsold,
            currentBid: null,
            highestBidderId: null,
            timer: BID_INTERVAL
        });

        await auctionRef.collection('log').add({
            message: `UNSOLD: ${playerName}`,
            timestamp: Date.now(),
            type: 'UNSOLD'
        });

        if (state.playerSelectionMode === 'AUTO') {
             setTimeout(() => startAuction(), 3000);
        }

      } catch (e: any) {
          console.error("Pass Player Error", e);
          alert("Pass Failed: " + e.message);
      }
  };

  const resetCurrentPlayer = async () => {
      if (!activeAuctionId) {
          alert("Error: No active auction. Refresh page.");
          return;
      }
      try {
          const auctionRef = db.collection('auctions').doc(activeAuctionId);
          await auctionRef.update({
              currentBid: 0,
              highestBidderId: null, 
              timer: BID_INTERVAL,
              status: AuctionStatus.InProgress 
          });
          await auctionRef.collection('log').add({
              message: "Current Player Reset by Admin (Bids Cleared)",
              timestamp: Date.now(),
              type: 'SYSTEM'
          });
          alert("Player reset successfully. Bids cleared.");
      } catch(e: any) {
          console.error("Reset Player Failed:", e);
          alert("Reset Player Failed: " + e.message);
      }
  };

  const resetAuction = async () => {
    if (!activeAuctionId) {
        alert("Error: No active auction.");
        return;
    }

    try {
        console.log("Starting Full Reset...");
        const auctionRef = db.collection('auctions').doc(activeAuctionId);

        const auctionSnap = await auctionRef.get();
        if (!auctionSnap.exists) throw new Error("Auction data not found");
        const auctionData = auctionSnap.data() as any;
        const defaultPurse = Number(auctionData.purseValue) || 10000;

        const teamsSnap = await auctionRef.collection('teams').get();
        const playersSnap = await auctionRef.collection('players').get();
        const logsSnap = await auctionRef.collection('log').get();

        const batch = db.batch();

        batch.update(auctionRef, {
            status: AuctionStatus.NotStarted,
            currentPlayerId: null,
            currentBid: null,
            highestBidderId: null,
            timer: BID_INTERVAL,
            adminViewOverride: null 
        });

        teamsSnap.docs.forEach(doc => {
            batch.update(doc.ref, {
                budget: defaultPurse,
                players: []
            });
        });

        playersSnap.docs.forEach(doc => {
            batch.update(doc.ref, {
                status: firebase.firestore.FieldValue.delete(),
                soldPrice: firebase.firestore.FieldValue.delete(),
                soldTo: firebase.firestore.FieldValue.delete()
            });
        });

        logsSnap.docs.forEach(doc => {
            batch.delete(doc.ref);
        });

        await batch.commit();

        await auctionRef.collection('log').add({
            message: 'FULL AUCTION RESET by Admin. All data restored.',
            timestamp: Date.now(),
            type: 'SYSTEM'
        });

        alert("Auction Fully Reset to 'Not Started'. Teams and Players restored.");
    } catch (e: any) {
        console.error("Full Reset Failed:", e);
        alert("Reset Failed: " + e.message);
    }
  };

  const endAuction = async () => {
      if (!activeAuctionId) return;
      await db.collection('auctions').doc(activeAuctionId).update({ 
          status: AuctionStatus.Finished,
          currentPlayerId: null,
          currentBid: null,
          highestBidderId: null,
          adminViewOverride: null
      });
      await db.collection('auctions').doc(activeAuctionId).collection('log').add({
          message: "Auction Manually Completed by Admin.",
          timestamp: Date.now(),
          type: 'SYSTEM'
      });
  }

  const startAuction = async (specificPlayerId?: string | number): Promise<boolean> => {
    if (!activeAuctionId) return false;
    try {
        const auctionRef = db.collection('auctions').doc(activeAuctionId);
        const playersSnap = await auctionRef.collection('players').get();
        const players = playersSnap.docs.map(d => ({id: d.id, ...d.data()} as Player));
        let nextPlayer: Player | undefined;

        if (specificPlayerId) {
             nextPlayer = players.find(p => String(p.id) === String(specificPlayerId));
        } else {
             const availablePlayers = players.filter(p => p.status !== 'SOLD' && p.status !== 'UNSOLD');
             if (state.playerSelectionMode === 'AUTO') {
                 if (availablePlayers.length > 0) {
                     const randomIndex = Math.floor(Math.random() * availablePlayers.length);
                     nextPlayer = availablePlayers[randomIndex];
                 }
             } else {
                 availablePlayers.sort((a,b) => {
                    const idA = Number(a.id);
                    const idB = Number(b.id);
                    if (!isNaN(idA) && !isNaN(idB)) return idA - idB;
                    return String(a.id).localeCompare(String(b.id));
                 });
                 nextPlayer = availablePlayers[0];
             }
        }

        if (!nextPlayer) {
            return false;
        }

        await auctionRef.update({
            status: AuctionStatus.InProgress,
            currentPlayerId: nextPlayer.id,
            currentBid: 0, 
            highestBidderId: null,
            timer: BID_INTERVAL,
            adminViewOverride: null
        });

        await auctionRef.collection('log').add({
            message: `Up for Auction: ${nextPlayer.name} (Base: ${nextPlayer.basePrice})`,
            timestamp: Date.now(),
            type: 'SYSTEM'
        });

        return true;

    } catch (e: any) {
        console.error("Start Auction Error", e);
        alert("Start Failed: " + e.message);
        return false;
    }
  };

  const resetUnsoldPlayers = async () => {
      if (!activeAuctionId) return;
      try {
          const auctionRef = db.collection('auctions').doc(activeAuctionId);
          const snapshot = await auctionRef.collection('players').where('status', '==', 'UNSOLD').get();

          if (snapshot.empty) {
              alert("No unsold players found to reset.");
              return;
          }

          const batch = db.batch();
          snapshot.docs.forEach(doc => {
              batch.update(doc.ref, { status: firebase.firestore.FieldValue.delete() });
          });

          await batch.commit();

          await auctionRef.collection('log').add({
              message: `ADMIN ACTION: ${snapshot.size} Unsold Players returned to pool.`,
              timestamp: Date.now(),
              type: 'SYSTEM'
          });
          alert(`${snapshot.size} Unsold players have been moved back to the available pool.`);
      } catch (e: any) {
          console.error("Error resetting unsold:", e);
          alert("Failed to delete unsold status: " + e.message);
      }
  };

  const handleLogout = () => {
      auth.signOut();
      setUserProfile(null);
      localStorage.removeItem('sm_sports_team_session');
  };

  const derivedCurrentPlayerIndex = state.players.findIndex(p => String(p.id) === String(state.currentPlayerId));
  const derivedState = { 
      ...state, 
      currentPlayerIndex: derivedCurrentPlayerIndex !== -1 ? derivedCurrentPlayerIndex : null 
  };

  return (
    <AuctionContext.Provider value={{ 
        state: derivedState, 
        userProfile, 
        setUserProfile,
        placeBid,
        sellPlayer,
        passPlayer,
        correctPlayerSale,
        startAuction,
        endAuction,
        resetAuction,
        resetCurrentPlayer,
        resetUnsoldPlayers,
        updateBiddingStatus, // Replaces toggleBidding
        toggleSelectionMode,
        updateTheme,
        setAdminView,
        logout: handleLogout,
        error,
        joinAuction,
        activeAuctionId,
        nextBid: calculateNextBid()
    }}>
      {children}
    </AuctionContext.Provider>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { useAuction } from '../hooks/useAuction';
import { AuctionStatus, Team, Player, ProjectorLayout, OBSLayout, BiddingStatus } from '../types';
import { Play, Check, X, ArrowLeft, Loader2, RotateCcw, AlertOctagon, DollarSign, Cast, Lock, Unlock, Monitor, ChevronDown, ChevronUp, Shuffle, Search, User, Palette, Trophy, Gavel, Settings, List, TrendingUp, Users, EyeOff } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const LiveAdminPanel: React.FC = () => {
  const { state, sellPlayer, passPlayer, startAuction, endAuction, resetAuction, resetCurrentPlayer, resetUnsoldPlayers, updateBiddingStatus, toggleSelectionMode, updateTheme, activeAuctionId, placeBid, nextBid, setAdminView } = useAuction();
  const { teams, players, biddingStatus, playerSelectionMode, adminViewOverride } = state;
  const navigate = useNavigate();

  const [isProcessing, setIsProcessing] = useState(false);
  const [isSellingMode, setIsSellingMode] = useState(false);
  const [selectedTeamId, setSelectedTeamId] = useState<string>('');
  const [finalPrice, setFinalPrice] = useState<number>(0);
  const [manualPlayerId, setManualPlayerId] = useState<string>('');
  const [playerSearchTerm, setPlayerSearchTerm] = useState('');
  const [showPlayerDropdown, setShowPlayerDropdown] = useState(false);

  // Settings Drawer State
  const [showSettings, setShowSettings] = useState(false);

  // Media Control State
  const [squadViewTeamId, setSquadViewTeamId] = useState('');

  // Derived State
  const availablePlayersCount = useMemo(() => players.filter(p => p.status !== 'SOLD' && p.status !== 'UNSOLD').length, [players]);
  const unsoldCount = useMemo(() => players.filter(p => p.status === 'UNSOLD').length, [players]);
  const isRoundActive = state.status === AuctionStatus.InProgress && state.currentPlayerId;
  const isStartDisabled = isProcessing || (state.status === AuctionStatus.NotStarted && (teams.length === 0 || availablePlayersCount === 0));

  // Filter Players for Manual Selection
  const filteredManualPlayers = useMemo(() => {
      const available = players.filter(p => p.status !== 'SOLD' && p.status !== 'UNSOLD');
      if (!playerSearchTerm) return available;
      return available.filter(p => 
          p.name.toLowerCase().includes(playerSearchTerm.toLowerCase()) || 
          p.category.toLowerCase().includes(playerSearchTerm.toLowerCase())
      );
  }, [players, playerSearchTerm]);

  // Auto-fill price and leader
  useEffect(() => {
      if (state.currentBid !== null) {
          setFinalPrice(Number(state.currentBid));
          if (state.highestBidder) {
              setSelectedTeamId(String(state.highestBidder.id));
          } else if (!isSellingMode) {
              setSelectedTeamId('');
          }
      }
  }, [state.currentBid, state.highestBidder, isSellingMode]);

  const handleStart = async (specificId?: string) => {
      if (teams.length === 0) return alert("No teams added.");
      if (availablePlayersCount === 0) return alert("No players available.");

      setIsProcessing(true);
      const hasNextPlayer = await startAuction(specificId);

      if (!hasNextPlayer) {
          if (window.confirm("No more players available. Mark Auction as Completed?")) {
              await endAuction();
          }
      } else {
          setManualPlayerId('');
          setPlayerSearchTerm('');
      }
      setIsProcessing(false);
  }

  const handleAdminBid = async (team: Team) => {
       if (isProcessing) return;
       if (state.highestBidder?.id === team.id) return; // Already leading
       if (team.budget < nextBid) return; // Insufficient funds

       try {
           await placeBid(team.id, nextBid);
       } catch(e) {
           console.error(e);
       }
  };

  const confirmSell = async () => {
      if (!selectedTeamId || finalPrice <= 0) return alert("Invalid sale details.");
      setIsProcessing(true);
      try {
          await sellPlayer(selectedTeamId, finalPrice);
          setIsSellingMode(false);
      } catch(e) { console.error(e); } finally { setIsProcessing(false); }
  };

  const handlePass = async () => {
      if (window.confirm("Confirm UNSOLD?")) {
          setIsProcessing(true);
          await passPlayer();
          setIsProcessing(false);
      }
  }

  const handleResetPlayer = async () => {
      if(window.confirm("Reset current player round?")) {
          setIsProcessing(true);
          await resetCurrentPlayer();
          setIsProcessing(false);
      }
  }

  const handleResetFull = async () => {
      if(window.confirm("WARNING: Reset ENTIRE auction to Not Started?")) {
          setIsProcessing(true);
          await resetAuction();
          setIsProcessing(false);
      }
  }

  const copyOBSLink = (type: 'transparent' | 'green') => {
      if (!activeAuctionId) return;
      const baseUrl = window.location.href.split('#')[0];
      const route = type === 'green' ? 'obs-green' : 'obs-overlay';
      navigator.clipboard.writeText(`${baseUrl}#/${route}/${activeAuctionId}`);
      alert("Link copied to clipboard!");
  };

  // --- Broadcast Control Handlers ---
  const handleViewChange = async (type: string, data?: any) => {
      const isSameType = adminViewOverride?.type === type;
      let isSameData = true;
      if (type === 'SQUAD') {
          isSameData = adminViewOverride?.data?.teamId === data?.teamId;
      }
      if (isSameType && isSameData && type !== 'NONE') {
          await setAdminView(null);
          return;
      }
      if (type === 'NONE') {
          await setAdminView(null);
      } else {
          await setAdminView({ type: type as any, data });
      }
  };

  const renderMainControls = () => {
       // Finish Auction Option
       if (availablePlayersCount === 0 && state.status !== AuctionStatus.NotStarted && !isRoundActive) {
           return (
               <div className="bg-blue-900/40 p-3 rounded-lg border border-blue-500/30 text-center">
                   <p className="text-blue-200 text-xs mb-2 font-bold uppercase">Auction Pool Empty</p>
                   <div className="grid grid-cols-2 gap-2">
                      {unsoldCount > 0 && (
                           <button 
                               onClick={async () => { if(window.confirm(`Bring back ${unsoldCount} unsold?`)) { setIsProcessing(true); await resetUnsoldPlayers(); setIsProcessing(false); }}} 
                               className="bg-blue-600 hover:bg-blue-500 text-white text-[10px] font-bold py-2 rounded flex items-center justify-center gap-1"
                           >
                               <RotateCcw className="w-3 h-3"/> Unsold ({unsoldCount})
                           </button>
                      )}
                      <button 
                          onClick={async () => { if(window.confirm("Finish Auction & Enable Stats?")) { setIsProcessing(true); await endAuction(); setIsProcessing(false); }}} 
                          className={`bg-green-600 hover:bg-green-500 text-white text-[10px] font-bold py-2 rounded flex items-center justify-center gap-1 ${unsoldCount === 0 ? 'col-span-2' : ''}`}
                      >
                          <Trophy className="w-3 h-3"/> Finish & Stats
                      </button>
                   </div>
               </div>
           )
       }

       if (isRoundActive) {
           if (isSellingMode) {
               return (
                   <div className="bg-gray-800 p-2 rounded border border-gray-600 animate-fade-in">
                       <div className="flex justify-between items-center mb-2 border-b border-gray-700 pb-1">
                          <span className="text-white text-xs font-bold uppercase">Confirm Sale</span>
                          <button onClick={() => setIsSellingMode(false)} className="text-gray-400 hover:text-white"><X className="w-4 h-4"/></button>
                       </div>
                       <select value={selectedTeamId} onChange={e => setSelectedTeamId(e.target.value)} className="w-full bg-black text-white text-xs p-1.5 mb-2 rounded border border-gray-600 outline-none">
                           <option value="">Select Team</option>
                           {teams.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                       </select>
                       <div className="relative mb-2">
                           <DollarSign className="absolute left-2 top-1/2 -translate-y-1/2 w-3 h-3 text-green-500"/>
                           <input type="number" value={finalPrice} onChange={e => setFinalPrice(Number(e.target.value))} className="w-full bg-black text-white text-xs p-1.5 pl-6 rounded border border-gray-600 outline-none font-bold" />
                       </div>
                       <button onClick={confirmSell} disabled={isProcessing} className="w-full bg-green-600 hover:bg-green-500 text-white text-xs font-bold py-1.5 rounded shadow flex items-center justify-center">
                           {isProcessing ? <Loader2 className="w-3 h-3 animate-spin"/> : 'Confirm Sold'}
                       </button>
                   </div>
               )
           }

           return (
               <div className="grid grid-cols-2 gap-2 h-16">
                    <button onClick={() => setIsSellingMode(true)} disabled={isProcessing} className="bg-green-600 hover:bg-green-500 text-white font-bold rounded flex flex-col items-center justify-center shadow-lg active:scale-95 transition-all">
                        <Check className="w-6 h-6 mb-1"/> <span className="text-xs uppercase tracking-wider">SOLD</span>
                    </button>
                    <button onClick={handlePass} disabled={isProcessing} className="bg-red-600 hover:bg-red-500 text-white font-bold rounded flex flex-col items-center justify-center shadow-lg active:scale-95 transition-all">
                        <X className="w-6 h-6 mb-1"/> <span className="text-xs uppercase tracking-wider">UNSOLD</span>
                    </button>
               </div>
           )
       }

       // Start Controls
       if (playerSelectionMode === 'MANUAL') {
           return (
               <div className="space-y-2">
                   <div className="relative">
                       <input 
                           type="text" 
                           placeholder="Search player..." 
                           className="w-full bg-gray-900 text-white text-xs p-2.5 pl-8 rounded border border-gray-700 focus:border-highlight outline-none"
                           value={playerSearchTerm}
                           onChange={e => { setPlayerSearchTerm(e.target.value); setShowPlayerDropdown(true); }}
                           onFocus={() => setShowPlayerDropdown(true)}
                       />
                       <Search className="absolute left-2.5 top-2.5 w-3 h-3 text-gray-500" />
                       {showPlayerDropdown && (
                           <div className="absolute top-full left-0 right-0 max-h-48 overflow-y-auto bg-gray-800 border border-gray-700 z-50 rounded-b shadow-xl custom-scrollbar">
                               {filteredManualPlayers.length > 0 ? filteredManualPlayers.map(p => (
                                   <div key={p.id} onClick={() => { setManualPlayerId(String(p.id)); setPlayerSearchTerm(p.name); setShowPlayerDropdown(false); }} className="p-2 hover:bg-gray-700 text-xs text-white cursor-pointer border-b border-gray-700 last:border-0 flex justify-between">
                                       <span>{p.name}</span> <span className="text-gray-500">{p.category}</span>
                                   </div>
                               )) : <div className="p-2 text-xs text-gray-500 text-center">No matches</div>}
                           </div>
                       )}
                   </div>
                   <button onClick={() => handleStart(manualPlayerId)} disabled={isStartDisabled || !manualPlayerId} className="w-full bg-highlight hover:bg-teal-400 text-primary font-bold py-3 rounded flex items-center justify-center disabled:opacity-50 disabled:cursor-not-allowed shadow-lg active:scale-95 transition-all">
                       {isProcessing ? <Loader2 className="w-4 h-4 animate-spin mr-2"/> : <Play className="w-4 h-4 mr-2"/>} Start Selected
                   </button>
               </div>
           )
       }

       return (
           <button onClick={() => handleStart()} disabled={isStartDisabled} className="w-full h-16 bg-highlight hover:bg-teal-400 text-primary font-bold rounded flex flex-col items-center justify-center disabled:opacity-50 disabled:cursor-not-allowed shadow-lg active:scale-95 transition-all">
               {isProcessing ? <Loader2 className="w-6 h-6 animate-spin mb-1"/> : <Shuffle className="w-6 h-6 mb-1"/>} 
               <span className="text-xs uppercase tracking-wider">{state.status === AuctionStatus.NotStarted ? "Start Auction" : "Next Random Player"}</span>
           </button>
       )
  }

  return (
    <div className="h-full flex flex-col bg-secondary rounded-xl shadow-2xl border border-gray-700 overflow-hidden" onClick={() => setShowPlayerDropdown(false)}>
        {/* TOP HEADER */}
        <div className="bg-gray-800 p-3 flex justify-between items-center border-b border-gray-700 shrink-0">
            <h2 className="text-highlight font-bold uppercase tracking-wider text-sm flex items-center gap-2">
                <Gavel className="w-4 h-4"/> Admin
            </h2>

            <div className="flex gap-2 items-center">
                 {/* BIDDING STATUS DROPDOWN */}
                 <div className="relative">
                     <select 
                        value={biddingStatus} 
                        onChange={(e) => updateBiddingStatus(e.target.value as BiddingStatus)}
                        className={`appearance-none pl-6 pr-6 py-1 rounded text-[10px] font-bold uppercase tracking-wide border outline-none cursor-pointer transition-colors
                            ${biddingStatus === 'ON' ? 'bg-green-500/10 text-green-400 border-green-500/30 hover:bg-green-500/20' : 
                              biddingStatus === 'PAUSED' ? 'bg-yellow-500/10 text-yellow-400 border-yellow-500/30 hover:bg-yellow-500/20' :
