export interface PlayerRole {
    id?: string;
    name: string;
}

export interface Player {
  id: number | string;
  name: string;
  photoUrl: string;
  category: string; // Auction Category (MVP, Set 1)
  role: string;     // Player Type (Batsman, Bowler)
  basePrice: number;
  nationality: string;
  speciality: string; // Kept for backward compat, usually same as role
  stats: {
    matches: number;
    runs: number;
    wickets: number;
  };
  status?: 'SOLD' | 'UNSOLD';
  soldPrice?: number;
  soldTo?: string;
}

export interface RegisteredPlayer {
    id: string;
    fullName: string;
    mobile: string;
    playerType: string;
    gender: string;
    dob: string;
    profilePic: string;
    paymentScreenshot: string;
    status: 'PENDING' | 'APPROVED' | 'REJECTED';
    submittedAt: number;
    [key: string]: any; // For custom fields
}

export interface Team {
  id: number | string;
  name: string;
  shortName?: string;
  owner: string;
  logoUrl: string;
  budget: number;
  players: Player[];
  minPlayers?: number;
  maxPlayers?: number;
