import React, { useState, useMemo, useEffect } from 'react';
import { useAuction } from '../hooks/useAuction';
import { Player } from '../types';
import { Search, Filter, X, Clock, CheckCircle } from 'lucide-react';
import { db } from '../firebase';

type PlayerStatus = 'upcoming' | 'sold';

const PlayerPool: React.FC = () => {
  const { state, activeAuctionId } = useAuction();
  const { players, teams, currentPlayerIndex, unsoldPlayers } = state;
  const [activeTab, setActiveTab] = useState<PlayerStatus>('upcoming');
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedRole, setSelectedRole] = useState<string>('All');
  const [availableRoles, setAvailableRoles] = useState<string[]>([]);

  // Fetch Roles dynamically to populate filter
  useEffect(() => {
      if(!activeAuctionId) return;
      const unsub = db.collection('auctions').doc(activeAuctionId).collection('roles').onSnapshot(s => {
          setAvailableRoles(s.docs.map(d => d.data().name));
      });
      return () => unsub();
  }, [activeAuctionId]);

  const soldPlayerIds = useMemo(() => new Set(teams.flatMap(team => team.players.map(p => p.id))), [teams]);
  const currentPlayer = currentPlayerIndex !== null ? unsoldPlayers[currentPlayerIndex] : null;

  const filteredPlayers = useMemo(() => {
    let list: (Omit<Player, 'status'> & { status: PlayerStatus, soldTo?: string, teamLogo?: string })[] = [];

    if (activeTab === 'upcoming') {
        list = unsoldPlayers.filter(p => !soldPlayerIds.has(p.id)).map(p => ({ ...p, status: 'upcoming' as PlayerStatus }));
    } else if (activeTab === 'sold') {
        teams.forEach(team => {
            team.players.forEach(player => {
                list.push({ ...player, status: 'sold' as PlayerStatus, soldTo: team.name, teamLogo: team.logoUrl });
            });
        });
    }

    if (selectedRole !== 'All') {
        list = list.filter(p => p.role === selectedRole || (!p.role && p.category === selectedRole)); // Fallback to category if role undefined
    }

    if (searchTerm) {
        const term = searchTerm.toLowerCase();
        list = list.filter(p => p.name.toLowerCase().includes(term));
    }

    return list;
  }, [activeTab, players, teams, soldPlayerIds, unsoldPlayers, searchTerm, selectedRole]);

  const TabButton: React.FC<{tab: PlayerStatus, label: string, icon: React.ReactNode}> = ({tab, label, icon}) => (
      <button 
        onClick={() => setActiveTab(tab)}
        className={`flex-1 py-3 text-sm font-bold flex items-center justify-center gap-2 transition-all duration-300 border-b-2 ${activeTab === tab ? 'border-highlight text-highlight bg-highlight/5' : 'border-transparent text-text-secondary hover:text-white hover:bg-white/5'}`}
      >
          {icon} {label}
      </button>
  );

  return (
    <div className="bg-secondary rounded-xl shadow-xl h-full flex flex-col border border-gray-700 overflow-hidden">
      <div className="p-4 bg-primary/30 border-b border-gray-700">
        <h2 className="text-lg font-bold text-white mb-4 flex items-center gap-2"><span className="w-1 h-6 bg-highlight rounded-full"></span>Player Pool</h2>

        <div className="space-y-3">
            <div className="relative group">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-gray-500 group-focus-within:text-highlight transition-colors" />
                <input type="text" placeholder="Search by name..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} className="w-full bg-primary border border-gray-600 rounded-lg py-2.5 pl-10 pr-10 text-text-main text-sm focus:outline-none focus:ring-1 focus:ring-highlight focus:border-highlight transition-all" />
                {searchTerm && <button onClick={() => setSearchTerm('')} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500 hover:text-red-400 transition-colors"><X className="h-4 w-4" /></button>}
            </div>

            <div className="relative">
                <Filter className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-gray-500" />
                <select value={selectedRole} onChange={(e) => setSelectedRole(e.target.value)} className="w-full bg-primary border border-gray-600 rounded-lg py-2.5 pl-10 pr-8 text-text-main text-sm focus:outline-none focus:ring-1 focus:ring-highlight focus:border-highlight appearance-none cursor-pointer transition-all">
                    <option value="All">All Roles</option>
                    {availableRoles.length > 0 ? availableRoles.map((role) => <option key={role} value={role}>{role}</option>) : (
                        // Fallback if no roles defined yet
                        ['Batsman', 'Bowler', 'All Rounder', 'Wicket Keeper'].map(r => <option key={r} value={r}>{r}</option>)
                    )}
                </select>
            </div>
        </div>
      </div>

      <div className="flex border-b border-gray-700 bg-primary/20">
        <TabButton tab="upcoming" label="Upcoming" icon={<Clock className="w-4 h-4"/>} />
        <TabButton tab="sold" label="Sold" icon={<CheckCircle className="w-4 h-4"/>} />
      </div>

      <div className="flex-grow overflow-y-auto p-2 custom-scrollbar">
        {filteredPlayers.length > 0 ? (
            <div className="space-y-2">
                {filteredPlayers.map(player => (
                    <div key={player.id} className={`p-3 rounded-lg flex items-center gap-3 transition-all border ${player.id === currentPlayer?.id && activeTab === 'upcoming' ? 'bg-highlight/10 border-highlight shadow-[0_0_10px_rgba(56,178,172,0.2)]' : 'bg-primary/40 border-transparent hover:border-gray-600 hover:bg-primary/60'}`}>
                        <img src={player.photoUrl} alt={player.name} className="w-10 h-10 rounded-full object-cover border border-gray-600"/>
                        <div className="flex-grow min-w-0">
                            <h4 className="font-bold text-text-main text-sm truncate">{player.name}</h4>
                            <div className="flex gap-2 text-xs">
                                <span className="text-highlight font-medium truncate">{player.role}</span>
                                <span className="text-gray-500">|</span>
                                <span className="text-text-secondary truncate">{player.category}</span>
                            </div>
                        </div>
                        <div className="text-right">
                            {player.status === 'upcoming' ? (
                                <span className="inline-block px-2 py-1 bg-gray-700 rounded text-xs text-gray-300 font-mono">{player.basePrice}</span>
                            ) : (
                                <div className="flex flex-col items-end">
                                    <span className="text-[10px] text-gray-500 uppercase tracking-wider">Sold To</span>
                                    <div className="flex items-center gap-1.5 mt-0.5">
                                        {player.teamLogo && <img src={player.teamLogo} alt="" className="w-4 h-4 rounded-full bg-gray-800" />}
                                        <span className="text-xs font-bold text-highlight truncate max-w-[80px]">{player.soldTo}</span>
                                    </div>
                                </div>
                            )}
                        </div>
                    </div>
                ))}
            </div>
        ) : (
            <div className="h-full flex flex-col items-center justify-center text-text-secondary opacity-50">
                <Search className="w-8 h-8 mb-2" />
                <p className="text-sm">No players found</p>
            </div>
        )}
      </div>
    </div>
  );
};

export default PlayerPool;

export enum PlayerCategory {
  Batsman = "Batsman",
  Bowler = "Bowler",
  AllRounder = "All-Rounder",
  Wicketkeeper = "Wicketkeeper",
}

export interface PlayerRole {
    id?: string;
    name: string;
    basePrice: number; // Default base price for this role
}

export interface Player {
  id: number | string;
  name: string;
  photoUrl: string;
  category: string; // Auction Category (Group: MVP, Set 1, Uncapped)
  role: string;     // Player Type (Skill: Batsman, Bowler)
  basePrice: number;
  nationality: string;
  speciality: string; // Kept for backward compat, usually same as role
  stats: {
    matches: number;
    runs: number;
    wickets: number;
  };
  status?: 'SOLD' | 'UNSOLD';
  soldPrice?: number;
  soldTo?: string;
}

export interface RegisteredPlayer {
    id: string;
    fullName: string;
    mobile: string;
    playerType: string;
    gender: string;
    dob: string;
    profilePic: string;
    paymentScreenshot: string;
    status: 'PENDING' | 'APPROVED' | 'REJECTED';
    submittedAt: number;
    [key: string]: any; // For custom fields
}

export interface Team {
  id: number | string;
  name: string;
  shortName?: string;
  owner: string;
  logoUrl: string;
  budget: number;
  players: Player[];
  minPlayers?: number;
  maxPlayers?: number;
  password?: string; // Added password for team login
}

export interface Bid {
  teamId: number | string;
  amount: number;
}

export enum AuctionStatus {
  NotStarted = "NOT_STARTED",
  InProgress = "IN_PROGRESS",
  Paused = "PAUSED",
  Sold = "SOLD",
  Unsold = "UNSOLD",
  Finished = "FINISHED",
}

export interface AuctionLog {
  message: string;
  timestamp: number;
  type: 'SYSTEM' | 'BID' | 'SOLD' | 'UNSOLD';
}

export interface BidIncrementSlab {
    from: number;
    increment: number;
}

export interface AuctionCategory {
    id?: string;
    name: string;
    basePrice: number;
    minPerTeam: number;
    maxPerTeam: number;
    bidIncrement: number;
    bidLimit: number;
    slabs: BidIncrementSlab[];
}

export interface Sponsor {
    id: string;
    name: string;
    imageUrl: string;
}

export interface SponsorConfig {
    showOnOBS: boolean;
    showOnProjector: boolean;
    loopInterval: number; // seconds
}

export type ProjectorLayout = 'STANDARD' | 'IPL' | 'MODERN';
export type OBSLayout = 'STANDARD' | 'MINIMAL' | 'VERTICAL';

export type AdminViewType = 'SQUAD' | 'PURSES' | 'UNSOLD' | 'SOLD' | 'TOP_BUY' | 'TOP_5' | 'NONE';

export interface AdminViewOverride {
    type: AdminViewType;
    data?: any; // e.g. { teamId: '...' }
}

export type BiddingStatus = 'ON' | 'PAUSED' | 'HIDDEN';

export interface AuctionState {
  players: Player[];
  teams: Team[];
  unsoldPlayers: Player[]; // This is the pool of available players
  categories: AuctionCategory[]; // Available categories with rules
  status: AuctionStatus;
  currentPlayerId: string | number | null; // Source of truth for current player
  currentPlayerIndex: number | null; // Derived helper
  currentBid: number | null;
  highestBidder: Team | null;
  timer: number;
  bidIncrement: number; // Global fallback increment
  bidSlabs?: BidIncrementSlab[]; // Global fallback slabs
  auctionLog: AuctionLog[];
  biddingStatus: BiddingStatus; // Replaces biddingEnabled
  playerSelectionMode: 'MANUAL' | 'AUTO';
  auctionLogoUrl?: string;
  tournamentName?: string;
  sponsors: Sponsor[];
  sponsorConfig: SponsorConfig;
  projectorLayout: ProjectorLayout;
  obsLayout: OBSLayout;
  adminViewOverride: AdminViewOverride | null;
}

export enum UserRole {
  SUPER_ADMIN = 'SUPER_ADMIN',
  ADMIN = 'ADMIN',
  TEAM_OWNER = 'TEAM_OWNER',
  VIEWER = 'VIEWER'
}

export interface UserProfile {
  uid: string;
  email: string;
  name?: string;
  role: UserRole;
  teamId?: number | string; // If role is TEAM_OWNER
}

export type FieldType = 'text' | 'number' | 'email' | 'select' | 'date' | 'file' | 'textarea';

export interface FormField {
    id: string;
    label: string;
    type: FieldType;
    required: boolean;
    options?: string[]; // For select inputs
    placeholder?: string;
}

export interface RegistrationConfig {
    isEnabled: boolean;
    fee: number;
    upiId: string;
    upiName: string;
    qrCodeUrl: string;
    terms: string;
    bannerUrl?: string; // Optional tournament logo
    customFields: FormField[];
}

export interface AuctionSetup {
    id?: string;
    title: string;
    sport: string;
    date: string;
    plan: string;
    totalTeams: number;
    purseValue: number;
    basePrice: number;
    bidIncrement: number;
    slabs?: BidIncrementSlab[]; // Global slabs for auction
    playersPerTeam: number;
    status: 'DRAFT' | 'LIVE' | 'COMPLETED';
    createdAt: number;
    createdBy?: string;
    registrationConfig?: RegistrationConfig;
    logoUrl?: string;
    bannerUrl?: string;
    playerSelectionMode?: 'MANUAL' | 'AUTO';
    sponsors?: Sponsor[];
    sponsorConfig?: SponsorConfig;
    projectorLayout?: ProjectorLayout;
    obsLayout?: OBSLayout;
}

export interface AuctionContextType {
    state: AuctionState;
    userProfile: UserProfile | null;
    setUserProfile: (profile: UserProfile) => void;
    placeBid: (teamId: number | string, amount: number) => Promise<void>;
    sellPlayer: (teamId?: string | number, customPrice?: number) => Promise<void>;
    passPlayer: () => Promise<void>;
    correctPlayerSale: (playerId: string, newTeamId: string | null, newPrice: number) => Promise<void>;
    startAuction: (specificPlayerId?: string | number) => Promise<boolean>;
    endAuction: () => Promise<void>;
    resetAuction: () => Promise<void>;
    resetCurrentPlayer: () => Promise<void>;
    resetUnsoldPlayers: () => Promise<void>;
    updateBiddingStatus: (status: BiddingStatus) => Promise<void>; // Updated from toggleBidding
    toggleSelectionMode: () => Promise<void>; // Toggle Auto/Manual
    updateTheme: (type: 'PROJECTOR' | 'OBS', layout: string) => Promise<void>;
    setAdminView: (view: AdminViewOverride | null) => Promise<void>;
    logout: () => void;
    error: string | null;
    joinAuction: (id: string) => void;
    activeAuctionId: string | null;
    nextBid: number; 
}

import React, { useEffect, useState, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { db, auth } from '../firebase';
import { AuctionSetup, Team, AuctionCategory, RegistrationConfig, FormField, RegisteredPlayer, Player, Sponsor, SponsorConfig, BidIncrementSlab, PlayerRole } from '../types';
import { ArrowLeft, Plus, Trash2, X, Image as ImageIcon, AlertTriangle, Layers, TrendingUp, FileText, QrCode, Link as LinkIcon, Save, Settings, AlignLeft, List, Calendar, Upload, Users, Eye, CheckCircle, XCircle, Key, Hash, Edit, Loader2, Database, DollarSign, Cast, Monitor, PenTool, FileSpreadsheet, UserPlus, Tag, Briefcase } from 'lucide-react';
import firebase from 'firebase/compat/app';
import { useAuction } from '../hooks/useAuction';
import * as XLSX from 'xlsx';

const AuctionManage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  // We use useAuction here primarily for the correctPlayerSale function which contains complex transaction logic
  const { correctPlayerSale } = useAuction();

  const [auction, setAuction] = useState<AuctionSetup | null>(null);
  const [loading, setLoading] = useState(true);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<'teams' | 'types' | 'categories' | 'registration' | 'registrations' | 'pool' | 'sponsors'>('teams');

  // Data States
  const [teams, setTeams] = useState<Team[]>([]);
  const [categories, setCategories] = useState<AuctionCategory[]>([]);
  const [playerRoles, setPlayerRoles] = useState<PlayerRole[]>([]); // New State for Types
  const [registrations, setRegistrations] = useState<RegisteredPlayer[]>([]);
  const [poolPlayers, setPoolPlayers] = useState<Player[]>([]);
  const [sponsors, setSponsors] = useState<Sponsor[]>([]);
  const [sponsorConfig, setSponsorConfig] = useState<SponsorConfig>({ showOnOBS: true, showOnProjector: true, loopInterval: 5 });

  // Registration Config State
  const [regConfig, setRegConfig] = useState<RegistrationConfig>({
      isEnabled: false,
      fee: 1500,
      upiId: '',
      upiName: '',
      qrCodeUrl: '',
      terms: '* Player registration fees is Rs. 1500, which is to be paid on below given UPI details.\n* Make payment and attach the screenshot of successful payment with registration form.\n* Player name will be included in auction list only after payment is confirmed.',
      bannerUrl: '',
      customFields: []
  });
  const qrInputRef = useRef<HTMLInputElement>(null);
  const bannerInputRef = useRef<HTMLInputElement>(null);

  // UI States
  const [showTeamModal, setShowTeamModal] = useState(false);
  const [editingTeam, setEditingTeam] = useState<Team | null>(null);
  const [showCategoryModal, setShowCategoryModal] = useState(false);
  const [showRoleModal, setShowRoleModal] = useState(false); // New Modal for Roles
  const [isSavingConfig, setIsSavingConfig] = useState(false);
  const [isApproving, setIsApproving] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);

  // Player Edit/Bulk States
  const [editingPlayer, setEditingPlayer] = useState<Player | null>(null);
  const [showPlayerModal, setShowPlayerModal] = useState(false);
  const [showBulkPriceModal, setShowBulkPriceModal] = useState(false);
  const [showAddPlayerModal, setShowAddPlayerModal] = useState(false);
  const [isImporting, setIsImporting] = useState(false);
  const excelInputRef = useRef<HTMLInputElement>(null);

  // Registration View Modal
  const [selectedRegistration, setSelectedRegistration] = useState<RegisteredPlayer | null>(null);

  // Auction Edit Modal
  const [showEditAuctionModal, setShowEditAuctionModal] = useState(false);

  // Sponsor Modal
  const [showSponsorModal, setShowSponsorModal] = useState(false);

  // Edit Sale Modal
  const [editingSalePlayer, setEditingSalePlayer] = useState<Player | null>(null);

  // Real-time Listener for Auction Details
  useEffect(() => {
    if (!id) return;

    setLoading(true);
    const unsubscribe = db.collection('auctions').doc(id).onSnapshot((docSnap) => {
        if (docSnap.exists) {
            const data = { id: docSnap.id, ...docSnap.data() } as AuctionSetup;
            setAuction(data);
            if (data.registrationConfig) {
                setRegConfig({
                    ...data.registrationConfig,
                    customFields: data.registrationConfig.customFields || []
                });
            }
            if (data.sponsorConfig) setSponsorConfig(data.sponsorConfig);
            setErrorMsg(null);
        } else {
            console.error("Auction not found");
            setErrorMsg("Auction not found.");
        }
        setLoading(false);
    }, (error: any) => {
        console.error("Error fetching auction details:", error);
        if (error.message?.includes("database") || error.code === 'not-found') {
            setErrorMsg("CRITICAL: Database not found. Create 'Firestore Database' in Firebase Console.");
        } else {
            setErrorMsg(error.message);
        }
        setLoading(false);
    });

    return () => unsubscribe();
  }, [id]);

  // Real-time Listeners
  useEffect(() => {
      if (!id) return;
      const unsubTeams = db.collection('auctions').doc(id).collection('teams').onSnapshot(s => setTeams(s.docs.map(d => ({ id: d.id, ...d.data() } as Team))));
      const unsubCats = db.collection('auctions').doc(id).collection('categories').onSnapshot(s => setCategories(s.docs.map(d => ({ id: d.id, ...d.data() } as AuctionCategory))));
      const unsubRoles = db.collection('auctions').doc(id).collection('roles').onSnapshot(s => setPlayerRoles(s.docs.map(d => ({ id: d.id, ...d.data() } as PlayerRole))));
      const unsubRegs = db.collection('auctions').doc(id).collection('registrations').onSnapshot(s => setRegistrations(s.docs.map(d => ({ id: d.id, ...d.data() } as RegisteredPlayer))));
      const unsubPlayers = db.collection('auctions').doc(id).collection('players').onSnapshot(s => setPoolPlayers(s.docs.map(d => ({ id: d.id, ...d.data() } as Player))));
      const unsubSponsors = db.collection('auctions').doc(id).collection('sponsors').onSnapshot(s => setSponsors(s.docs.map(d => ({ id: d.id, ...d.data() } as Sponsor))));

      return () => {
          unsubTeams(); unsubCats(); unsubRoles(); unsubRegs(); unsubPlayers(); unsubSponsors();
      };
  }, [id]);

  const updateAuctionField = async (field: keyof AuctionSetup, value: any) => {
      if (!id) return;
      try {
          await db.collection('auctions').doc(id).update({ [field]: value });
      } catch (e: any) {
          console.error(e);
          alert("Failed to update setting: " + e.message);
      }
  };

  const handleDeleteTeam = async (teamId: string) => {
      if (!id || !auth.currentUser) return alert("You must be logged in to delete teams.");
      if (window.confirm(`Are you sure you want to delete this team (ID: ${teamId})? This cannot be undone.`)) {
          try {
              await db.collection('auctions').doc(id).collection('teams').doc(teamId).delete();
          } catch (e: any) {
              alert("Failed to delete team: " + e.message);
          }
      }
  };

  const handleDeleteCategory = async (catId: string) => {
      if (!id) return;
      if (window.confirm("Delete this category?")) {
          try {
              await db.collection('auctions').doc(id).collection('categories').doc(catId).delete();
          } catch (e) {
              console.error("Error deleting category:", e);
          }
      }
  };

  const handleDeleteRole = async (roleId: string) => {
      if (!id) return;
      if (window.confirm("Delete this player type? Players assigned to this type will not be deleted but type label may be lost.")) {
          try {
              await db.collection('auctions').doc(id).collection('roles').doc(roleId).delete();
          } catch (e) {
              console.error("Error deleting role:", e);
          }
      }
  };

  const handleDeletePoolPlayer = async (playerId: string) => {
      if (!id || !auth.currentUser) return alert("Please login first.");
      if (window.confirm("Are you sure? This will remove the player from the auction pool.")) {
          try {
              await db.collection('auctions').doc(id).collection('players').doc(playerId.toString()).delete();
          } catch (e: any) {
              alert("Error deleting player: " + e.message);
          }
      }
  };

  const handleClearPool = async () => {
      if (!id || !auth.currentUser) return alert("Please login first.");
      if (window.confirm("DANGER: This will delete ALL players from the auction pool. This cannot be undone. Are you sure?")) {
          setIsDeleting(true);
          try {
              const snapshot = await db.collection('auctions').doc(id).collection('players').get();
              if (snapshot.empty) {
                  alert("Pool is already empty.");
                  setIsDeleting(false);
                  return;
              }
              const batch = db.batch();
              let count = 0;
              snapshot.docs.forEach((doc) => {
                  batch.delete(doc.ref);
                  count++;
              });
              if (count > 0) {
                  await batch.commit();
                  alert(`Successfully deleted ${count} players.`);
              }
          } catch (e: any) {
              alert("Failed to delete all players: " + e.message);
          } finally {
              setIsDeleting(false);
          }
      }
  };

  const handleApprovePlayer = async (reg: RegisteredPlayer, selectedCategory: string, selectedBasePrice: number) => {
      if (!id || !auth.currentUser) return alert("You are not logged in.");
      setIsApproving(true);

      let safePhotoUrl = '';
      if (reg.profilePic && reg.profilePic.length < 500000) safePhotoUrl = reg.profilePic;

      const newPlayerId = db.collection('dummy').doc().id; 

      const playerData: Player = {
          id: String(newPlayerId),
          name: String(reg.fullName || 'Unknown Player'),
          category: String(selectedCategory || 'Uncategorized'),
          role: String(reg.playerType || 'General'),
          basePrice: Number(selectedBasePrice || 0),
          nationality: 'India',
          photoUrl: safePhotoUrl,
          speciality: String(reg.playerType || 'General'),
          stats: { matches: 0, runs: 0, wickets: 0 }
      };

      try {
          await db.collection('auctions').doc(id).collection('players').doc(newPlayerId).set(playerData);
          await db.collection('auctions').doc(id).collection('registrations').doc(reg.id).update({ status: 'APPROVED' });
          alert("Player Approved Successfully!");
          setSelectedRegistration(null);
      } catch (e: any) {
          alert(`Failed to approve: ${e.message}`);
      } finally {
          setIsApproving(false);
      }
  };

  const handleRejectPlayer = async (regId: string) => {
      if (!id || !auth.currentUser) return alert("You are not logged in.");
      if (window.confirm("Are you sure you want to reject (DELETE) this registration?")) {
          try {
              await db.collection('auctions').doc(id).collection('registrations').doc(regId).delete();
              alert("Registration Deleted.");
              setSelectedRegistration(null);
          } catch (e: any) {
              alert("Failed to delete: " + e.message);
          }
      }
  };

  const handleSaveRegConfig = async () => {
      if (!id) return;
      setIsSavingConfig(true);
      try {
          await db.collection('auctions').doc(id).update({ registrationConfig: regConfig });
          alert("Configuration Saved!");
      } catch (e) {
          alert("Failed to save configuration.");
      } finally {
          setIsSavingConfig(false);
      }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>, field: 'qr' | 'banner') => {
      const file = e.target.files?.[0];
      if (file) {
          if (file.size > 800 * 1024) return alert("Image too large. Max 800KB.");
          const reader = new FileReader();
          reader.onloadend = () => {
              setRegConfig(prev => ({ ...prev, [field === 'qr' ? 'qrCodeUrl' : 'bannerUrl']: reader.result as string }));
          };
          reader.readAsDataURL(file);
      }
  };

  const copyRegLink = () => {
      navigator.clipboard.writeText(`${window.location.origin}/#/auction/${id}/register`);
      alert("Registration Link Copied!");
  };

  const copyOBSLink = (type: 'transparent' | 'green') => {
      if (!id) return;
      if (window.location.protocol === 'blob:') return alert("Deploy to use OBS Overlay.");
      const baseUrl = window.location.href.split('#')[0];
      const route = type === 'green' ? 'obs-green' : 'obs-overlay';
      navigator.clipboard.writeText(`${baseUrl}#/${route}/${id}`);
      alert(`${type === 'green' ? 'GREEN SCREEN' : 'TRANSPARENT'} OBS URL Copied!`);
  }

  // --- SMART EXCEL IMPORT ---
  const handleExcelImport = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file || !id) return;

      setIsImporting(true);
      try {
          const data = await file.arrayBuffer();
          const workbook = XLSX.read(data);
          const worksheet = workbook.Sheets[workbook.SheetNames[0]];
          const jsonData = XLSX.utils.sheet_to_json(worksheet);

          if (jsonData.length === 0) {
              alert("Excel file appears empty.");
              return;
          }

          let successCount = 0;
          let failCount = 0;

          // 1. Identify missing Categories and Roles from Excel
          const uniqueCategories = new Set<string>();
          const uniqueRoles = new Set<string>();

          jsonData.forEach((row: any) => {
              const cat = row['Category'] || row['category'] || row['Group'] || 'Uncategorized';
              const role = row['Type'] || row['type'] || row['Role'] || row['role'] || 'General';
              if(cat) uniqueCategories.add(String(cat).trim());
              if(role) uniqueRoles.add(String(role).trim());
          });

          // 2. Auto-Create missing Categories
          // Also try to find if base price is mentioned in excel, but categories are unique so we just use default if creating
          const existingCatNames = categories.map(c => c.name);
          const defaultBase = auction?.basePrice || 20;

          for (const catName of Array.from(uniqueCategories)) {
              if (!existingCatNames.includes(catName)) {
                  // Create new category with default values
                  await db.collection('auctions').doc(id).collection('categories').add({
                      name: catName,
                      basePrice: defaultBase,
                      minPerTeam: 0,
                      maxPerTeam: 100,
                      bidIncrement: auction?.bidIncrement || 10,
                      bidLimit: 0,
                      slabs: []
                  });
              }
          }

          // 3. Auto-Create missing Roles
          const existingRoleNames = playerRoles.map(r => r.name);
          for (const roleName of Array.from(uniqueRoles)) {
              if (!existingRoleNames.includes(roleName)) {
                  await db.collection('auctions').doc(id).collection('roles').add({
                      name: roleName,
                      basePrice: defaultBase // Default to auction base price
                  });
              }
          }

          // Refresh local state lists to ensure correct mapping in loop (though firestore listener will update eventually, we need immediate lookup)
          // We'll trust the names match.

          // 4. Batch Import Players
          let batch = db.batch();
          let batchCount = 0;
          const BATCH_LIMIT = 450;

          for (const row of jsonData as any[]) {
               const name = row['Name'] || row['name'] || row['Player Name'] || row['Player'];
               const categoryName = String(row['Category'] || row['category'] || row['Group'] || 'Uncategorized').trim();
               const roleName = String(row['Type'] || row['type'] || row['Role'] || row['role'] || 'General').trim();

               let basePrice = 0;
               // Priority: Excel Row > Category Default > Role Default > Auction Default
               if (row['Base Price'] || row['Price'] || row['BasePrice']) {
                   basePrice = Number(row['Base Price'] || row['Price'] || row['BasePrice']);
               } else {
                   // Lookup Category
                   const catObj = categories.find(c => c.name === categoryName);
                   if (catObj && catObj.basePrice > 0) {
                       basePrice = catObj.basePrice;
                   } else {
                       // Lookup Role
                       const roleObj = playerRoles.find(r => r.name === roleName);
                       if (roleObj && roleObj.basePrice > 0) {
                           basePrice = roleObj.basePrice;
                       } else {
                           basePrice = defaultBase;
                       }
                   }
               }

               if (name) {
                   const newId = db.collection('dummy').doc().id;
                   const playerRef = db.collection('auctions').doc(id).collection('players').doc(newId);

                   batch.set(playerRef, {
                       id: String(newId),
                       name: String(name).trim(),
                       category: categoryName,
                       role: roleName,
                       basePrice: Number(basePrice),
                       nationality: 'India',
                       photoUrl: '', 
                       speciality: roleName,
                       stats: { matches: 0, runs: 0, wickets: 0 },
                       status: 'OPEN'
                   });

                   successCount++;
                   batchCount++;

                   if (batchCount >= BATCH_LIMIT) {
                       await batch.commit();
                       batch = db.batch();
                       batchCount = 0;
                   }
               } else {
                   failCount++;
               }
          }

          if (batchCount > 0) {
              await batch.commit();
          }

          alert(`Imported ${successCount} players successfully! Auto-created missing categories/roles.`);

      } catch (err: any) {
          console.error("Excel Import Error:", err);
          alert("Failed to import Excel: " + err.message);
      } finally {
          setIsImporting(false);
          if (excelInputRef.current) excelInputRef.current.value = '';
      }
